const raw = $json.output || $json.text || '';
let data;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  data = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  return [{ json: {
    error: true,
    message: 'El agente no devolvio un JSON valido. Intentalo de nuevo.',
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  } }];
}

const ctxPrep = $('Preparar Input Agente').first().json;

// BRANCH convertir_presupuesto: marcamos flag para que el IF downstream
// dispare la rama HTTP que consulta el detalle del presupuesto.
if (data.tipo === 'convertir_presupuesto') {
  if (!data.presupuesto_id) {
    return [{ json: {
      error: true,
      message: 'No tengo el ID del presupuesto. Reformula tu mensaje indicando el numero (ej: P2026-0042).',
      raw_from: ctxPrep.raw_from,
      phone_number_id: ctxPrep.phone_number_id
    }}];
  }
  return [{ json: {
    _needs_presupuesto_fetch: true,
    data,
    org_id: ctxPrep.org_id,
    raw_from: ctxPrep.raw_from,
    phone_number_id: ctxPrep.phone_number_id,
  }}];
}

// BRANCH normal: calculo de totales con las lineas devueltas por el agente.
const lineas = (data.lineas || []).map(l => ({
  concepto: l.descripcion || l.concepto || 'Servicio',
  cantidad: Number(l.cantidad) || 1,
  precio_unitario: Number(l.precio_unitario) || 0,
  iva_pct: l.iva_pct !== undefined ? Number(l.iva_pct) : 21,
  descuento_pct: Number(l.descuento_pct) || 0,
}));

const subtotales = lineas.map(l => {
  const bruto = l.cantidad * l.precio_unitario;
  const descLinea = bruto * (l.descuento_pct / 100);
  return { base: bruto - descLinea, iva_pct: l.iva_pct, bruto, _isNuevo: l._isNuevo };
});

const descGlobalPct = Number(data.descuento_global_pct) || 0;
const subtotal = subtotales.reduce((s, l) => s + l.base, 0);
const descGlobal = subtotal * (descGlobalPct / 100);
const baseTotal = subtotal - descGlobal;
const ivaTotal = subtotales.reduce((s, l) => s + l.base * (1 - descGlobalPct / 100) * (l.iva_pct / 100), 0);
const total = baseTotal + ivaTotal;

const fmtCalc = n => n.toFixed(2).replace('.', ',');
const tipoLabel = (data.tipo || 'factura').toUpperCase();
const lineLines = [];
lineLines.push(tipoLabel);
lineLines.push(`Cliente: ${data.cliente?.nombre || 'Sin nombre'}`);
lineLines.push('---');
for (const l of lineas) {
  const bruto = l.cantidad * l.precio_unitario;
  lineLines.push(`- ${l.cantidad}x ${l.concepto}: ${fmtCalc(l.precio_unitario)} EUR/u = ${fmtCalc(bruto)} EUR`);
  if (l.descuento_pct > 0) {
    lineLines.push(`  Dto linea -${l.descuento_pct}%: -${fmtCalc(bruto * l.descuento_pct / 100)} EUR`);
  }
}
lineLines.push('---');
lineLines.push(`Base: ${fmtCalc(baseTotal)} EUR`);
if (descGlobalPct > 0) {
  lineLines.push(`Dto global ${descGlobalPct}%: -${fmtCalc(descGlobal)} EUR`);
}
lineLines.push(`IVA: ${fmtCalc(ivaTotal)} EUR`);
lineLines.push(`TOTAL: ${fmtCalc(total)} EUR`);
lineLines.push('');
lineLines.push('Responde "si" para Confirmar, describe la correccion, o "cancelar".');

return [{ json: {
  error: false,
  _needs_presupuesto_fetch: false,
  data,
  resumen: lineLines.join('\n'),
  totales: { base: Number(baseTotal.toFixed(2)), iva: Number(ivaTotal.toFixed(2)), total: Number(total.toFixed(2)) },
  nuevos_productos: lineas.filter(l => l._isNuevo).map(l => ({ nombre: l.concepto, precio_orientativo: l.precio_unitario, iva_pct: l.iva_pct })),
  raw_from: ctxPrep.raw_from,
  phone_number_id: ctxPrep.phone_number_id,
}}];

